use std::collections::HashSet;
use std::sync::{Arc, Mutex};

struct ConcurrentIdTracker {
    set: Arc<Mutex<HashSet<u32>>>, 
}

impl ConcurrentIdTracker {
    fn new() -> Self {
        ConcurrentIdTracker { set: Arc::new(Mutex::new(HashSet::new())) }
    }

    fn add_id(&self, id: u32) {
        let mut guard = self.set.lock().unwrap();
        guard.insert(id);
    }

    fn check_id(&self, id: u32) -> bool {
        let guard = self.set.lock().unwrap();
        guard.contains(&id)
    }
}

fn main() {
    let tracker = Arc::new(ConcurrentIdTracker::new());
    let mut handles = vec![];

    for i in 0..10 { 
        let tracker_clone = Arc::clone(&tracker);
        let handle = std::thread::spawn(move || {
            if i % 2 == 0 {
                tracker_clone.add_id(i * 3 + 1);
            } else {
                tracker_clone.check_id(i * 5);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("All operations complete.");
    let final_check = tracker.check_id(10); 
    println!("Checking for ID 10 after concurrency test: {}", final_check);
}

