use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};
use std::f64;

struct BloomFilter {
    bits: Vec<bool>,
    k: usize,
    m: usize,
}

impl BloomFilter {
    fn new(expected_items: usize, false_positive_rate: f64) -> Self {
        let m = (-(expected_items as f64) * (1.0 - false_positive_rate).ln() / (false_positive_rate).ln()).round().max(1.0) as usize;
        let k = ((m as f64 / expected_items as f64) * (2.0_f64).sqrt()).round().max(1.0) as usize;
        BloomFilter {
            bits: vec![false; m],
            k,
            m,
        }
    }

    fn add(&mut self, item: &str) {
        let mut hasher = DefaultHasher::new();
        item.hash(&mut hasher);
        let hash_value = hasher.finish() as usize;

        for i in 0..self.k {
            let index = (hash_value + i * 19) & self.m - 1;
            if index < self.m && index >= 0 {
                self.bits[index] = true;
            }
        }
    }

    fn might_contain(&self, item: &str) -> bool {
        let mut hasher = DefaultHasher::new();
        item.hash(&mut hasher);
        let hash_value = hasher.finish() as usize;

        for i in 0..self.k {
            let index = (hash_value + i * 19) & self.m - 1;
            if index >= self.m || !self.bits[index] {
                return false;
            }
        }
        true
    }
}

use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};
use std::f64;

struct BloomFilter {
    bits: Vec<bool>,
    size: usize,
}

impl BloomFilter {
    fn new(expected_items: usize, false_positive_rate: f64) -> Self {
        let m = (expected_items as f64 * (f64::ln(2.0) / -f64::ln(1.0 - false_positive_rate))).round() as usize;
        let k = (1.0 / expected_items as f64 * m as f64).max(1.0).floor() as usize;

        BloomFilter {
            bits: vec![false; m],
            size: m,
        }
    }

    fn add(&mut self, item: &str) {
        let mut hasher = DefaultHasher::new();
        item.hash(&mut hasher);
        let hash_val = hasher.finish() as usize;

        for i in 0..self.bits.len() / 32 + 1 {
            let index = (hash_val >> (i * 32)) & (self.size - 1);
            self.bits[index] = true;
        }
    }

    fn might_contain(&self, item: &str) -> bool {
        let mut hasher = DefaultHasher::new();
        item.hash(&mut hasher);
        let hash_val = hasher.finish() as usize;

        for i in 0..3 {
            let index = ((hash_val >> (i * 32)) & (self.size - 1));
            if !self.bits[index] {
                return false;
            }
        }
        true
    }
}

fn main() {
    let mut filter = BloomFilter::new(5, 0.01);
    filter.add("source_file:a.rs");
    filter.add("transpiler_pass:optimize");

    println!("Checking 'source_file:a.rs': {}", if filter.might_contain("source_file:a.rs") { "Possibly present" } else { "Definitely not present" });
    println!("Checking 'unknown_feature:xyz': {}", if filter.might_contain("unknown_feature:xyz") { "Possibly present" } else { "Definitely not present" });
}

use std::collections::HashSet;

struct RateLimiter {
    seen_items: HashSet<String>,
}

impl RateLimiter {
    fn new() -> Self {
        RateLimiter { seen_items: HashSet::new() }
    }

    fn check_and_add(&mut self, item: &str) -> bool {
        if self.seen_items.contains(item) {
            return true;
        }
        self.seen_items.insert(String::from(item));
        false
    }

    fn is_present(&self, item: &str) -> bool {
        self.seen_items.contains(item)
    }
}
